export class Customer {
  constructor(
    readonly id: CustomerId,
    readonly document: TaxDocument,
  ) {}

  canReceiveInvoice() {
    return this.document.isValid();
  }
}

export class RegisterCustomer {
  constructor(private gateway: CustomerGateway) {}

  execute(input: RegisterCustomerInput) {
    const customer = Customer.create(input);
    return this.gateway.save(customer);
  }
}

@Component({ templateUrl: './customer-profile.page.html' })
export class CustomerProfilePage {
  customer = inject(CustomerFacade).current();
}

export class Invoice {
  markAsPaid(payment: Payment) {
    if (this.isCanceled) throw new Error('Invoice canceled');
    return { ...this, paidAt: payment.date };
  }
}

@Injectable()
export class BillingFacade {
  overdueInvoices = signal<Invoice[]>([]);
  pay(invoice: Invoice) { return this.payInvoice.execute(invoice.id); }
}

export function canUpgrade(plan: Plan, target: Plan) {
  return target.price > plan.price && plan.status === 'active';
}

export class Money {
  constructor(readonly cents: number, readonly currency = 'BRL') {}
  add(value: Money) { return new Money(this.cents + value.cents, this.currency); }
}
